    }
}

package tests;

import db.DBUtils;
import org.testng.Assert;
import org.testng.annotations.Test;

import java.sql.Connection;
import java.sql.ResultSet;
import java.sql.Statement;

public class DBConnectionTest {

    @Test
    public void testDBConnection() throws Exception {
        try (Connection conn = DBUtils.getConnection();
             Statement stmt = conn.createStatement();
             ResultSet rs = stmt.executeQuery("SELECT 1")) {

            rs.next();
            int result = rs.getInt(1);
            System.out.println("DB Connected! SELECT 1 returned: " + result);
            Assert.assertEquals(result, 1, "Expected SELECT 1 to return 1");
        }
    }
}

package tests;

import db.DBQuery;
import org.testng.Assert;
import org.testng.annotations.Test;

public class DBSmokeTest {

    @Test
    public void verifySeedDataCounts() throws Exception {
        int students = DBQuery.getCount("students");
        int courses = DBQuery.getCount("courses");
        int enrollments = DBQuery.getCount("enrollments");

        System.out.println("students=" + students);
        System.out.println("courses=" + courses);
        System.out.println("enrollments=" + enrollments);

        Assert.assertTrue(students > 0, "Students table should not be empty");
        Assert.assertTrue(courses > 0, "Courses table should not be empty");
        Assert.assertTrue(enrollments > 0, "Enrollments table should not be empty");
    }

    @Test
    public void verifyStudentExistsUsingRealId() throws Exception {
        int id = DBQuery.getAnyStudentId();
        boolean exists = DBQuery.studentExists(id);

        System.out.println("Checking student_id=" + id + " exists: " + exists);

        Assert.assertTrue(exists, "Expected student_id=" + id + " to exist");
    }
}

package tests;

import db.DBQuery;
import org.testng.Assert;
import org.testng.annotations.Test;

public class DBSmokeTest {

    @Test
    public void verifySeedDataCounts() throws Exception {
        int users = DBQuery.getUserCount();
        int courses = DBQuery.getCourseCount();
        int enrollments = DBQuery.getEnrollmentCount();

        System.out.println("users=" + users);
        System.out.println("courses=" + courses);
        System.out.println("enrollments=" + enrollments);

        Assert.assertTrue(users >= 2, "app_user should include seeded admin1 and student1");
        Assert.assertTrue(courses >= 2, "course should include seeded CS612 and CS632P");
        Assert.assertTrue(enrollments >= 0, "enrollment count should be non-negative");
    }

    @Test
    public void verifyStudentExistsUsingRealId() throws Exception {
        long id = DBQuery.getAnyStudentUserId();
        boolean exists = DBQuery.appUserExists(id);

        System.out.println("Checking app_user.id=" + id + " exists: " + exists);

        Assert.assertTrue(exists, "Expected app_user.id=" + id + " to exist");
    }
}

package utils;

import java.io.InputStream;
import java.util.Properties;

public class ConfigReader {

    private static Properties properties = new Properties();

    static {
        try {
            InputStream input =
                    ConfigReader.class
                            .getClassLoader()
                            .getResourceAsStream("config.properties");

            if (input == null) {
                throw new RuntimeException("config.properties not found");
            }

            properties.load(input);

        } catch (Exception e) {
            throw new RuntimeException("Failed to load config.properties", e);
        }
    }

    public static String get(String key) {
        return properties.getProperty(key);
    }
}

package utils;

import java.io.InputStream;
import java.util.Properties;

public class ConfigReader {

    private static final Properties properties = new Properties();

    static {
        try {
            InputStream input =
                    ConfigReader.class
                            .getClassLoader()
                            .getResourceAsStream("config.properties");

            if (input == null) {
                throw new RuntimeException("config.properties not found");
            }

            properties.load(input);

        } catch (Exception e) {
            throw new RuntimeException("Failed to load config.properties", e);
        }
    }

    public static String get(String key) {
        String value = properties.getProperty(key);
        if (value == null || value.isBlank()) {
            throw new IllegalStateException("Missing required config key: " + key);
        }
        return value;
    }
}
